import type { FastifyReply, FastifyRequest } from "fastify";
import type { Permission, SeedMembership, SeedStore, SessionState } from "./seed.js";

export interface ApiSessionContext {
  token: string;
  userId: string;
  projectId: string | null;
  permissions: Permission[];
}

export interface ApiErrorBody {
  error: {
    code: string;
    message: string;
    requestId: string;
  };
}

export function requestIdFor(request: FastifyRequest): string {
  return String(request.id).startsWith("req_") ? String(request.id) : `req_${request.id}`;
}

export function errorResponse(
  request: FastifyRequest,
  code: string,
  message: string
): ApiErrorBody {
  return {
    error: {
      code,
      message,
      requestId: requestIdFor(request)
    }
  };
}

export function sendError(
  request: FastifyRequest,
  reply: FastifyReply,
  statusCode: number,
  code: string,
  message: string
): FastifyReply {
  return reply.status(statusCode).send(errorResponse(request, code, message));
}

function parseBearer(header: unknown): string | null {
  if (typeof header !== "string") {
    return null;
  }

  const parts = header.trim().split(/\s+/u);
  if (parts.length !== 2 || parts[0] !== "Bearer" || !parts[1]) {
    return null;
  }

  return parts[1];
}

function membershipFor(store: SeedStore, userId: string, projectId: string): SeedMembership | undefined {
  return store.memberships.find(
    (membership) => membership.userId === userId && membership.projectId === projectId
  );
}

export function getPermissionsForSelectedProject(store: SeedStore, session: SessionState): Permission[] {
  if (!session.selectedProjectId) {
    return [];
  }
  return membershipFor(store, session.userId, session.selectedProjectId)?.permissions ?? [];
}

export function authenticateRequest(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore
): ApiSessionContext | FastifyReply {
  const authorization = request.headers.authorization;
  if (authorization === undefined) {
    return sendError(request, reply, 401, "auth_missing", "Missing bearer token.");
  }

  const token = parseBearer(authorization);
  if (!token) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const userId = store.tokens[token];
  if (!userId) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const session = store.sessionsByToken[token] ?? { userId, selectedProjectId: null };
  store.sessionsByToken[token] = session;

  return {
    token,
    userId,
    projectId: session.selectedProjectId,
    permissions: getPermissionsForSelectedProject(store, session)
  };
}

export function requireProjectMembership(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore,
  session: ApiSessionContext,
  projectId: string
): SeedMembership | FastifyReply {
  const projectExists = store.projects.some((project) => project.id === projectId);
  const membership = membershipFor(store, session.userId, projectId);

  if (!projectExists || !membership) {
    return sendError(request, reply, 403, "project_forbidden", "Project is not available for this session.");
  }

  return membership;
}

export function requireSelectedProject(
  request: FastifyRequest,
  reply: FastifyReply,
  session: ApiSessionContext,
  projectId: string
): true | FastifyReply {
  if (session.projectId !== projectId) {
    return sendError(request, reply, 403, "project_not_selected", "Select this project before using project resources.");
  }

  return true;
}

export function requirePermission(
  request: FastifyRequest,
  reply: FastifyReply,
  membership: SeedMembership,
  permission: Permission
): true | FastifyReply {
  if (!membership.permissions.includes(permission)) {
    return sendError(request, reply, 403, "project_forbidden", "Project permission is required.");
  }

  return true;
}

import Fastify, { type FastifyInstance, type FastifyReply } from "fastify";
import cors from "@fastify/cors";
import {
  authenticateRequest,
  getPermissionsForSelectedProject,
  requestIdFor,
  requirePermission,
  requireProjectMembership,
  requireSelectedProject,
  sendError
} from "./auth.js";
import { createSeedStore, type ChatMessage, type SeedStore } from "./seed.js";

interface BuildServerOptions {
  store?: SeedStore;
}

interface ProjectParams {
  projectId: string;
}

interface LoginBody {
  email?: unknown;
  password?: unknown;
}

interface ChatBody {
  message?: unknown;
}

let messageSequence = 0;

function nextMessageId(): string {
  messageSequence += 1;
  return `msg_${String(messageSequence).padStart(6, "0")}`;
}

function bounded<T>(items: T[], limit: number): T[] {
  return items.slice(0, limit);
}

function isReply(value: unknown): value is FastifyReply {
  return typeof value === "object" && value !== null && "sent" in value;
}

function validateChatMessage(body: unknown): string | null {
  if (typeof body !== "object" || body === null || Array.isArray(body)) {
    return null;
  }

  const message = (body as ChatBody).message;
  if (typeof message !== "string") {
    return null;
  }

  const trimmed = message.trim();
  if (trimmed.length === 0 || trimmed.length > 1000) {
    return null;
  }

  return trimmed;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const store = options.store ?? createSeedStore();
  messageSequence = 0;

  const app = Fastify({
    logger: false,
    genReqId: (() => {
      let sequence = 0;
      return () => {
        sequence += 1;
        return `req_${String(sequence).padStart(6, "0")}`;
      };
    })()
  });

  void app.register(cors, { origin: true });

  app.get("/health", async (request) => ({
    ok: true,
    service: "building-agent-api",
    requestId: requestIdFor(request)
  }));

  app.post<{ Body: LoginBody }>("/api/login", async (request, reply) => {
    const { email, password } = request.body ?? {};
    if (typeof email !== "string" || typeof password !== "string" || !email.trim() || !password) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const user = store.users.find((candidate) => candidate.email === email && candidate.password === password);
    if (!user) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const token = Object.entries(store.tokens).find(([, userId]) => userId === user.id)?.[0];
    if (!token) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    store.sessionsByToken[token] = store.sessionsByToken[token] ?? { userId: user.id, selectedProjectId: null };

    return {
      token,
      user: { id: user.id, name: user.name },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/session", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      session: {
        userId: session.userId,
        projectId: session.projectId,
        permissions: session.permissions
      },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/projects", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const memberships = store.memberships.filter((membership) => membership.userId === session.userId);
    const projects = bounded(memberships, store.maxListSize).flatMap((membership) => {
      const project = store.projects.find((candidate) => candidate.id === membership.projectId);
      return project ? [{ id: project.id, name: project.name, permissions: membership.permissions }] : [];
    });

    return { projects, limit: store.maxListSize, requestId: requestIdFor(request) };
  });

  app.post<{ Params: ProjectParams }>("/api/projects/:projectId/select", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selectedSession = {
      userId: session.userId,
      selectedProjectId: request.params.projectId
    };
    store.sessionsByToken[session.token] = selectedSession;

    return {
      session: {
        userId: session.userId,
        projectId: request.params.projectId,
        permissions: getPermissionsForSelectedProject(store, selectedSession)
      },
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    return {
      messages: bounded(store.messagesByProject[request.params.projectId] ?? [], store.maxListSize),
      limit: store.maxListSize,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams; Body: ChatBody }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const writable = requirePermission(request, reply, membership, "chat:write");
    if (isReply(writable)) {
      return writable;
    }

    const content = validateChatMessage(request.body);
    if (!content) {
      return sendError(request, reply, 422, "chat_invalid", "Chat message must be 1-1000 characters.");
    }

    const messages = store.messagesByProject[request.params.projectId] ?? [];
    const message: ChatMessage = {
      id: nextMessageId(),
      projectId: request.params.projectId,
      userId: session.userId,
      role: "user",
      content
    };
    messages.push(message);
    if (messages.length > store.maxChatMessages) {
      messages.splice(0, messages.length - store.maxChatMessages);
    }
    store.messagesByProject[request.params.projectId] = messages;

    return reply.status(201).send({ message, requestId: requestIdFor(request) });
  });

  app.setErrorHandler((error, request, reply) => {
    if (error.validation) {
      return sendError(request, reply, 422, "chat_invalid", "Request payload is invalid.");
    }

    request.log.error({ err: error, requestId: requestIdFor(request) }, "Unhandled API error");
    return sendError(request, reply, 500, "internal_error", "Unexpected API error.");
  });

  return app;
}

export type Permission = "chat:read" | "chat:write";

export interface SeedUser {
  id: string;
  name: string;
  email: string;
  password: string;
}

export interface SeedProject {
  id: string;
  name: string;
}

export interface SeedMembership {
  userId: string;
  projectId: string;
  permissions: Permission[];
}

export interface ChatMessage {
  id: string;
  projectId: string;
  userId: string;
  role: "user";
  content: string;
}

export interface SessionState {
  userId: string;
  selectedProjectId: string | null;
}

export interface SeedStore {
  users: SeedUser[];
  tokens: Record<string, string>;
  projects: SeedProject[];
  memberships: SeedMembership[];
  messagesByProject: Record<string, ChatMessage[]>;
  sessionsByToken: Record<string, SessionState>;
  maxListSize: number;
  maxChatMessages: number;
}

export function createSeedStore(): SeedStore {
  const projects: SeedProject[] = [
    { id: "project_alpha", name: "Alpha Build" },
    { id: "project_beta", name: "Beta Build" },
    { id: "project_gamma", name: "Gamma Build" }
  ];

  return {
    users: [
      { id: "user_ada", name: "Ada Lovelace", email: "ada@example.test", password: "local-dev-password" },
      { id: "user_grace", name: "Grace Hopper", email: "grace@example.test", password: "local-dev-password" }
    ],
    tokens: {
      "seed-token-ada": "user_ada",
      "seed-token-grace": "user_grace"
    },
    projects,
    memberships: [
      { userId: "user_ada", projectId: "project_alpha", permissions: ["chat:read", "chat:write"] },
      { userId: "user_ada", projectId: "project_beta", permissions: ["chat:read"] },
      { userId: "user_grace", projectId: "project_gamma", permissions: ["chat:read", "chat:write"] }
    ],
    messagesByProject: Object.fromEntries(projects.map((project) => [project.id, [] as ChatMessage[]])),
    sessionsByToken: {},
    maxListSize: 50,
    maxChatMessages: 25
  };
}

export function cloneStore(store: SeedStore): SeedStore {
  return {
    users: store.users.map((user) => ({ ...user })),
    tokens: { ...store.tokens },
    projects: store.projects.map((project) => ({ ...project })),
    memberships: store.memberships.map((membership) => ({ ...membership, permissions: [...membership.permissions] })),
    messagesByProject: Object.fromEntries(
      Object.entries(store.messagesByProject).map(([projectId, messages]) => [
        projectId,
        messages.map((message) => ({ ...message }))
      ])
    ),
    sessionsByToken: Object.fromEntries(
      Object.entries(store.sessionsByToken).map(([token, session]) => [token, { ...session }])
    ),
    maxListSize: store.maxListSize,
    maxChatMessages: store.maxChatMessages
  };
}

export function seedStore(): SeedStore {
  return createSeedStore();
}

export interface ApiErrorDetail {
  code: string;
  message: string;
  requestId?: string | undefined;
}

export class ApiClientError extends Error {
  readonly code: string;
  readonly requestId: string | undefined;
  readonly status: number | undefined;

  constructor(detail: ApiErrorDetail, status?: number) {
    super(detail.message);
    this.name = "ApiClientError";
    this.code = detail.code;
    this.requestId = detail.requestId;
    this.status = status;
  }
}

export interface UserSummary {
  id: string;
  name: string;
}

export interface SessionSummary {
  userId: string;
  projectId: string | null;
  permissions: string[];
}

export interface ProjectSummary {
  id: string;
  name: string;
  permissions: string[];
}

export interface ChatMessage {
  id: string;
  projectId: string;
  userId: string;
  role: "user";
  content: string;
}

export interface LoginResponse {
  token: string;
  user: UserSummary;
  requestId: string;
}

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "";
const REQUEST_TIMEOUT_MS = 8000;

function apiUrl(path: string): string {
  return `${API_BASE_URL}${path}`;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function parseApiError(value: unknown): ApiErrorDetail | null {
  if (!isRecord(value) || !isRecord(value.error)) {
    return null;
  }
  const { code, message, requestId } = value.error;
  if (typeof code !== "string" || typeof message !== "string") {
    return null;
  }
  return { code, message, requestId: typeof requestId === "string" ? requestId : undefined };
}

function malformed(message = "The API returned an unreadable response."): ApiClientError {
  return new ApiClientError({ code: "api_malformed", message });
}

function unavailable(): ApiClientError {
  return new ApiClientError({ code: "api_unavailable", message: "Local API is unavailable. Check that the API dev server is running, then retry." });
}

async function readJson(response: Response): Promise<unknown> {
  try {
    return await response.json();
  } catch {
    throw malformed();
  }
}

async function requestJson(path: string, options: RequestInit = {}): Promise<unknown> {
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

  try {
    const response = await fetch(apiUrl(path), {
      ...options,
      headers: {
        "content-type": "application/json",
        ...options.headers
      },
      signal: controller.signal
    });
    const payload = await readJson(response);
    if (!response.ok) {
      const detail = parseApiError(payload) ?? { code: "api_malformed", message: "The API returned an error in an unexpected format." };
      throw new ApiClientError(detail, response.status);
    }
    return payload;
  } catch (error) {
    if (error instanceof ApiClientError) {
      throw error;
    }
    throw unavailable();
  } finally {
    window.clearTimeout(timeoutId);
  }
}

function authHeaders(token: string): HeadersInit {
  return { authorization: `Bearer ${token}` };
}

export async function login(email: string, password: string): Promise<LoginResponse> {
  const payload = await requestJson("/api/login", {
    method: "POST",
    body: JSON.stringify({ email, password })
  });
  if (!isRecord(payload) || typeof payload.token !== "string" || !isRecord(payload.user) || typeof payload.user.id !== "string" || typeof payload.user.name !== "string" || typeof payload.requestId !== "string") {
    throw malformed("Login returned an unexpected response.");
  }
  return { token: payload.token, user: { id: payload.user.id, name: payload.user.name }, requestId: payload.requestId };
}

export async function getSession(token: string): Promise<{ session: SessionSummary; requestId: string }> {
  const payload = await requestJson("/api/session", { headers: authHeaders(token) });
  if (!isRecord(payload) || !isRecord(payload.session) || typeof payload.session.userId !== "string" || !(typeof payload.session.projectId === "string" || payload.session.projectId === null) || !Array.isArray(payload.session.permissions) || typeof payload.requestId !== "string") {
    throw malformed("Session returned an unexpected response.");
  }
  return {
    session: {
      userId: payload.session.userId,
      projectId: payload.session.projectId,
      permissions: payload.session.permissions.filter((permission): permission is string => typeof permission === "string")
    },
    requestId: payload.requestId
  };
}

export async function listProjects(token: string): Promise<{ projects: ProjectSummary[]; requestId: string }> {
  const payload = await requestJson("/api/projects", { headers: authHeaders(token) });
  if (!isRecord(payload) || !Array.isArray(payload.projects) || typeof payload.requestId !== "string") {
    throw malformed("Projects returned an unexpected response.");
  }
  return {
    projects: payload.projects.flatMap((project): ProjectSummary[] => {
      if (!isRecord(project) || typeof project.id !== "string" || typeof project.name !== "string" || !Array.isArray(project.permissions)) {
        return [];
      }
      return [{ id: project.id, name: project.name, permissions: project.permissions.filter((permission): permission is string => typeof permission === "string") }];
    }),
    requestId: payload.requestId
  };
}

export async function selectProject(token: string, projectId: string): Promise<{ session: SessionSummary; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/select`, {
    method: "POST",
    headers: authHeaders(token)
  });
  if (!isRecord(payload) || !isRecord(payload.session) || typeof payload.session.userId !== "string" || typeof payload.session.projectId !== "string" || !Array.isArray(payload.session.permissions) || typeof payload.requestId !== "string") {
    throw malformed("Project selection returned an unexpected response.");
  }
  return {
    session: {
      userId: payload.session.userId,
      projectId: payload.session.projectId,
      permissions: payload.session.permissions.filter((permission): permission is string => typeof permission === "string")
    },
    requestId: payload.requestId
  };
}

export async function getChat(token: string, projectId: string): Promise<{ messages: ChatMessage[]; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/chat`, { headers: authHeaders(token) });
  if (!isRecord(payload) || !Array.isArray(payload.messages) || typeof payload.requestId !== "string") {
    throw malformed("Chat returned an unexpected response.");
  }
  return {
    messages: payload.messages.flatMap((message): ChatMessage[] => {
      if (!isRecord(message) || typeof message.id !== "string" || typeof message.projectId !== "string" || typeof message.userId !== "string" || message.role !== "user" || typeof message.content !== "string") {
        return [];
      }
      return [{ id: message.id, projectId: message.projectId, userId: message.userId, role: message.role, content: message.content }];
    }),
    requestId: payload.requestId
  };
}

export async function sendChatMessage(token: string, projectId: string, message: string): Promise<{ message: ChatMessage; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/chat`, {
    method: "POST",
    headers: authHeaders(token),
    body: JSON.stringify({ message })
  });
  if (!isRecord(payload) || !isRecord(payload.message) || typeof payload.message.id !== "string" || typeof payload.message.projectId !== "string" || typeof payload.message.userId !== "string" || payload.message.role !== "user" || typeof payload.message.content !== "string" || typeof payload.requestId !== "string") {
    throw malformed("Chat post returned an unexpected response.");
  }
  return {
    message: {
      id: payload.message.id,
      projectId: payload.message.projectId,
      userId: payload.message.userId,
      role: payload.message.role,
      content: payload.message.content
    },
    requestId: payload.requestId
  };
}

import { FormEvent, useEffect, useMemo, useState } from "react";
import {
  ApiClientError,
  getChat,
  getSession,
  listProjects,
  login,
  selectProject,
  sendChatMessage,
  type ChatMessage,
  type ProjectSummary,
  type SessionSummary,
  type UserSummary
} from "./api";

const STORAGE_KEY = "building-agent.session.v1";

interface StoredSession {
  token: string;
  user: UserSummary | null;
  projectId: string | null;
}

interface BannerState {
  tone: "error" | "info" | "success";
  title: string;
  message: string;
  code?: string | undefined;
  requestId?: string | undefined;
}

function readStoredSession(): StoredSession {
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return { token: "", user: null, projectId: null };
    }
    const parsed = JSON.parse(raw) as Partial<StoredSession>;
    return {
      token: typeof parsed.token === "string" ? parsed.token : "",
      user: parsed.user && typeof parsed.user.id === "string" && typeof parsed.user.name === "string" ? parsed.user : null,
      projectId: typeof parsed.projectId === "string" ? parsed.projectId : null
    };
  } catch {
    window.localStorage.removeItem(STORAGE_KEY);
    return { token: "", user: null, projectId: null };
  }
}

function storeSession(value: StoredSession): void {
  if (!value.token) {
    window.localStorage.removeItem(STORAGE_KEY);
    return;
  }
  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(value));
}

function errorBanner(error: unknown, title: string): BannerState {
  if (error instanceof ApiClientError) {
    return { tone: "error", title, message: error.message, code: error.code, requestId: error.requestId };
  }
  return { tone: "error", title, message: "Something went wrong. Please retry." };
}

function isAuthFailure(error: unknown): boolean {
  return error instanceof ApiClientError && (error.status === 401 || error.code === "auth_invalid" || error.code === "auth_missing");
}

function Banner({ banner }: { banner: BannerState | null }) {
  if (!banner) {
    return null;
  }
  return (
    <section className={`banner banner-${banner.tone}`} role={banner.tone === "error" ? "alert" : "status"} aria-live="polite">
      <strong>{banner.title}</strong>
      <p>{banner.message}</p>
      {(banner.code || banner.requestId) ? (
        <p className="diagnostic-line">
          {banner.code ? <span>Code: {banner.code}</span> : null}
          {banner.requestId ? <span>Request: {banner.requestId}</span> : null}
        </p>
      ) : null}
    </section>
  );
}

function LoginScreen({ onLogin, busy }: { onLogin: (email: string, password: string) => Promise<void>; busy: boolean }) {
  const [email, setEmail] = useState("ada@example.test");
  const [password, setPassword] = useState("local-dev-password");
  const [validation, setValidation] = useState("");

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!email.trim() || !password) {
      setValidation("Enter the seeded email and password to continue.");
      return;
    }
    setValidation("");
    await onLogin(email.trim(), password);
  }

  return (
    <main className="auth-card" aria-labelledby="login-title">
      <p className="eyebrow">Local seeded access</p>
      <h1 id="login-title">Sign in to BuildingAgent</h1>
      <p className="muted">Use the development credentials from the README. Anonymous access is intentionally disabled.</p>
      <form className="stack" onSubmit={handleSubmit}>
        <label>
          Email
          <input autoComplete="username" value={email} onChange={(event) => setEmail(event.target.value)} />
        </label>
        <label>
          Password
          <input type="password" autoComplete="current-password" value={password} onChange={(event) => setPassword(event.target.value)} />
        </label>
        {validation ? <p className="field-error" role="alert">{validation}</p> : null}
        <button type="submit" disabled={busy}>{busy ? "Signing in…" : "Sign in"}</button>
      </form>
    </main>
  );
}

function ProjectScreen({ projects, onSelect, busy }: { projects: ProjectSummary[]; onSelect: (project: ProjectSummary) => Promise<void>; busy: boolean }) {
  return (
    <main className="workspace-card" aria-labelledby="projects-title">
      <p className="eyebrow">Project boundary</p>
      <h1 id="projects-title">Choose an authorized project</h1>
      <p className="muted">Only projects returned by the API for this seeded session are selectable.</p>
      <div className="project-grid">
        {projects.map((project) => (
          <article className="project-card" key={project.id}>
            <div>
              <h2>{project.name}</h2>
              <p>{project.id}</p>
              <p className="permissions">{project.permissions.join(" · ") || "No chat permissions"}</p>
            </div>
            <button type="button" onClick={() => void onSelect(project)} disabled={busy}>
              Select project
            </button>
          </article>
        ))}
      </div>
    </main>
  );
}

function ChatWorkspace({ project, messages, onSend, busy }: { project: ProjectSummary; messages: ChatMessage[]; onSend: (message: string) => Promise<void>; busy: boolean }) {
  const [draft, setDraft] = useState("");
  const canWrite = project.permissions.includes("chat:write");

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!draft.trim()) {
      return;
    }
    const message = draft;
    await onSend(message);
    setDraft("");
  }

  return (
    <main className="workspace-card chat-shell" aria-labelledby="chat-title">
      <div>
        <p className="eyebrow">Selected project</p>
        <h1 id="chat-title">{project.name} workspace</h1>
        <p className="muted">Project id: <strong>{project.id}</strong></p>
      </div>
      <section className="message-list" aria-label={`${project.name} messages`}>
        {messages.length === 0 ? <p className="empty-state">No messages yet. Start with a project-scoped question.</p> : null}
        {messages.map((message) => (
          <article className="message" key={message.id}>
            <span>{message.userId}</span>
            <p>{message.content}</p>
          </article>
        ))}
      </section>
      <form className="composer" onSubmit={handleSubmit}>
        <label htmlFor="chat-message">Message</label>
        <textarea id="chat-message" value={draft} onChange={(event) => setDraft(event.target.value)} disabled={!canWrite || busy} placeholder={canWrite ? "Ask about this project…" : "This project is read-only for your account."} />
        <button type="submit" disabled={!canWrite || busy || !draft.trim()}>{busy ? "Sending…" : "Send message"}</button>
      </form>
      {!canWrite ? <p className="field-error" role="status">This project does not grant chat write permission.</p> : null}
    </main>
  );
}

export default function App() {
  const initial = useMemo(readStoredSession, []);
  const [token, setToken] = useState(initial.token);
  const [user, setUser] = useState<UserSummary | null>(initial.user);
  const [session, setSession] = useState<SessionSummary | null>(null);
  const [projects, setProjects] = useState<ProjectSummary[]>([]);
  const [selectedProject, setSelectedProject] = useState<ProjectSummary | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [banner, setBanner] = useState<BannerState | null>(null);
  const [busy, setBusy] = useState(false);
  const [bootstrapping, setBootstrapping] = useState(Boolean(initial.token));

  function clearAuth(nextBanner?: BannerState) {
    setToken("");
    setUser(null);
    setSession(null);
    setProjects([]);
    setSelectedProject(null);
    setMessages([]);
    storeSession({ token: "", user: null, projectId: null });
    setBanner(nextBanner ?? { tone: "info", title: "Signed out", message: "Sign in again to continue." });
  }

  useEffect(() => {
    if (!token) {
      setBootstrapping(false);
      return;
    }

    let cancelled = false;
    async function bootstrap() {
      setBootstrapping(true);
      try {
        const [sessionResponse, projectResponse] = await Promise.all([getSession(token), listProjects(token)]);
        if (cancelled) {
          return;
        }
        setSession(sessionResponse.session);
        setProjects(projectResponse.projects);
        const restoredProject = projectResponse.projects.find((project) => project.id === sessionResponse.session.projectId) ?? null;
        setSelectedProject(restoredProject);
        if (restoredProject) {
          const chatResponse = await getChat(token, restoredProject.id);
          if (!cancelled) {
            setMessages(chatResponse.messages);
          }
        }
        setBanner(null);
      } catch (error) {
        if (!cancelled) {
          if (isAuthFailure(error)) {
            clearAuth(errorBanner(error, "Session expired"));
          } else {
            setBanner(errorBanner(error, "Could not load session"));
          }
        }
      } finally {
        if (!cancelled) {
          setBootstrapping(false);
        }
      }
    }

    void bootstrap();
    return () => {
      cancelled = true;
    };
  }, [token]);

  async function handleLogin(email: string, password: string) {
    setBusy(true);
    try {
      const response = await login(email, password);
      setToken(response.token);
      setUser(response.user);
      storeSession({ token: response.token, user: response.user, projectId: null });
      setBanner({ tone: "success", title: "Signed in", message: `Welcome, ${response.user.name}.`, requestId: response.requestId });
    } catch (error) {
      setBanner(errorBanner(error, "Sign in failed"));
    } finally {
      setBusy(false);
    }
  }

  async function handleProjectSelect(project: ProjectSummary) {
    if (!token) {
      setBanner({ tone: "error", title: "Authentication required", message: "Sign in before selecting a project.", code: "auth_missing" });
      return;
    }
    setBusy(true);
    try {
      const selected = await selectProject(token, project.id);
      const chat = await getChat(token, project.id);
      setSession(selected.session);
      setSelectedProject(project);
      setMessages(chat.messages);
      storeSession({ token, user, projectId: project.id });
      setBanner({ tone: "success", title: "Project selected", message: `${project.name} is now active.`, requestId: selected.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Project selection failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  async function handleSend(message: string) {
    if (!token || !selectedProject) {
      setBanner({ tone: "error", title: "Select a project first", message: "Chat is available only after authentication and project selection.", code: "project_not_selected" });
      return;
    }
    if (!message.trim()) {
      setBanner({ tone: "error", title: "Message required", message: "Enter a non-empty message before sending.", code: "chat_invalid" });
      return;
    }
    setBusy(true);
    try {
      const posted = await sendChatMessage(token, selectedProject.id, message.trim());
      setMessages((current) => [...current, posted.message]);
      setBanner({ tone: "success", title: "Message sent", message: "The API accepted the project-scoped message.", requestId: posted.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Chat message failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  const authenticated = Boolean(token && user);

  return (
    <div className="app-shell">
      <header className="topbar">
        <div>
          <span className="brand-mark" aria-hidden="true">BA</span>
          <span className="brand-name">BuildingAgent</span>
        </div>
        {authenticated ? <button className="secondary" type="button" onClick={() => clearAuth()}>Sign out</button> : null}
      </header>
      <Banner banner={banner} />
      {bootstrapping ? <main className="workspace-card"><p>Checking your saved session…</p></main> : null}
      {!bootstrapping && !authenticated ? <LoginScreen onLogin={handleLogin} busy={busy} /> : null}
      {!bootstrapping && authenticated && !selectedProject ? <ProjectScreen projects={projects} onSelect={handleProjectSelect} busy={busy} /> : null}
      {!bootstrapping && authenticated && selectedProject ? <ChatWorkspace project={selectedProject} messages={messages} onSend={handleSend} busy={busy} /> : null}
      {session ? <footer className="diagnostic-footer">Session project: {session.projectId ?? "none selected"}</footer> : null}
    </div>
  );
}

